import React, { useState } from "react";
import Navbar from "../../components/Navbar";
import "../../App.css";

function AdminStockManagement() {
  const [stock, setStock] = useState([
    { name: "Milk", quantity: 20, expiry: "2026-01-10", price: 30 },
    { name: "Maggi", quantity: 40, expiry: "2026-03-01", price: 15 },
  ]);

  /* ================= MANUAL ADD STATE ================= */
  const [newItem, setNewItem] = useState({
    name: "",
    quantity: "",
    expiry: "",
    price: "",
  });

  const addItemManually = () => {
    if (!newItem.name || !newItem.quantity || !newItem.price) {
      alert("Please fill required fields");
      return;
    }

    setStock((prev) => [
      ...prev,
      {
        name: newItem.name,
        quantity: Number(newItem.quantity),
        expiry: newItem.expiry,
        price: Number(newItem.price),
      },
    ]);

    setNewItem({ name: "", quantity: "", expiry: "", price: "" });
  };

  /* ================= CSV PARSER ================= */
  const parseCSV = (text) => {
    const lines = text.trim().split("\n");
    const headers = lines[0].split(",").map((h) => h.trim());

    return lines.slice(1).map((line) => {
      const values = line.split(",").map((v) => v.trim());
      let obj = {};
      headers.forEach((h, i) => {
        obj[h] = values[i];
      });

      return {
        name: obj.name,
        quantity: Number(obj.quantity),
        expiry: obj.expiry,
        price: Number(obj.price),
      };
    });
  };

  /* ================= CSV UPLOAD ================= */
  const handleCSVUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    if (!file.name.endsWith(".csv")) {
      alert("Please upload a CSV file");
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const csvText = event.target.result;
      const parsedData = parseCSV(csvText);
      setStock((prev) => [...prev, ...parsedData]);
    };

    reader.readAsText(file);
  };

  return (
    <>
      <Navbar variant="dashboard" />

      <div className="container">
        {/* HEADER */}
        <div className="card">
          <h2>Admin – Stock Management</h2>
          <p className="note">
            Add products manually or upload inventory using CSV
          </p>
        </div>

        {/* MANUAL ADD */}
        <div className="card">
          <h3>Add Product Manually</h3>

          <form>
            <input
              placeholder="Product name"
              value={newItem.name}
              onChange={(e) =>
                setNewItem({ ...newItem, name: e.target.value })
              }
            />

            <input
              type="number"
              placeholder="Quantity"
              value={newItem.quantity}
              onChange={(e) =>
                setNewItem({ ...newItem, quantity: e.target.value })
              }
            />

            <input
              type="date"
              value={newItem.expiry}
              onChange={(e) =>
                setNewItem({ ...newItem, expiry: e.target.value })
              }
            />

            <input
              type="number"
              placeholder="Price"
              value={newItem.price}
              onChange={(e) =>
                setNewItem({ ...newItem, price: e.target.value })
              }
            />

            <button type="button" onClick={addItemManually}>
              Add Item
            </button>
          </form>
        </div>

        {/* CSV UPLOAD */}
        <div className="card">
          <h3>Upload Stock via CSV</h3>

          <input type="file" accept=".csv" onChange={handleCSVUpload} />

          <p className="note" style={{ marginTop: "10px" }}>
            CSV format: <br />
            <code>name,quantity,expiry,price</code>
          </p>
        </div>

        {/* STOCK TABLE */}
        <div className="card">
          <h3>Current Inventory</h3>

          {stock.length === 0 ? (
            <p className="note">No stock available</p>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>Product</th>
                  <th>Quantity</th>
                  <th>Expiry</th>
                  <th>Price</th>
                </tr>
              </thead>
              <tbody>
                {stock.map((item, index) => (
                  <tr key={index}>
                    <td>{item.name}</td>
                    <td>{item.quantity}</td>
                    <td>{item.expiry}</td>
                    <td>₹{item.price}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </>
  );
}

export default AdminStockManagement;
